// Consensus Dropout Explorer
const neurons = [
  { id: 'N2', name: 'Clausal Continuation', rate: 0.884, on: true },
  { id: 'N2361', name: 'Syntactic Elaboration', rate: 0.841, on: true },
  { id: 'N2460', name: 'Relational Embedding', rate: 0.860, on: true },
  { id: 'N2928', name: 'Sequential Structure', rate: 0.914, on: true },
  { id: 'N1831', name: 'Discourse Coherence', rate: 0.810, on: true },
  { id: 'N1245', name: 'Argument Structure', rate: 0.855, on: true },
  { id: 'N2600', name: 'Concrete Reference', rate: 0.792, on: false }
];

const consensus = neurons.filter(n => n.on).length;
const structural = neurons.slice(0, 6).filter(n => n.on).length;
const referential = neurons[6].on ? 1 : 0;

let diagnosis = '';
if (consensus === 7) diagnosis = 'FULL CONSENSUS: Script running normally. MLP intervention counterproductive (ΔP = -0.020).';
else if (consensus >= 5) diagnosis = `HIGH CONSENSUS (${consensus}/7): Mild deviation. MLP marginally ${consensus === 5 ? 'harmful' : 'helpful'}.`;
else if (consensus >= 3) diagnosis = `MODERATE (${consensus}/7): Exception handler active. MLP provides +0.03 ΔP.`;
else diagnosis = `LOW CONSENSUS (${consensus}/7): Full exception mode. MLP critical (+0.094 to +0.187 ΔP).`;

let failureType = '';
if (!neurons[6].on && structural === 6) failureType = 'REFERENTIAL FAILURE: Structure intact, but lost concrete grounding. Possible Schankian trigger: MTRANS (information transfer without physical anchor).';
else if (neurons[6].on && structural < 4) failureType = 'STRUCTURAL FAILURE: Concrete referent present but grammar disrupted. Possible trigger: PTRANS (physical event disrupting discourse flow).';
else if (structural < 4 && !neurons[6].on) failureType = 'COMPOUND FAILURE: Both structure and reference lost. Script abandonment — requires new frame selection.';
else if (consensus < 5) failureType = 'MIXED FAILURE: Partial dropout across dimensions. Operator selection depends on specific pattern.';
else failureType = 'NO SIGNIFICANT FAILURE: Within normal processing range.';

return `Consensus: ${consensus}/7 (Structural: ${structural}/6, Referential: ${referential}/1)\n\n${diagnosis}\n\n${failureType}`;

// Consensus level distribution and MLP effect
const levels = [
  { level: '0/7', tokens: 206, deltaP: +0.187, ci: '[+0.145, +0.231]', effect: '▲▲▲ MLP CRITICAL' },
  { level: '1/7', tokens: 913, deltaP: +0.094, ci: '[+0.079, +0.109]', effect: '▲▲ MLP very helpful' },
  { level: '2/7', tokens: 3051, deltaP: +0.045, ci: '[+0.039, +0.051]', effect: '▲ MLP helpful' },
  { level: '3/7', tokens: 6283, deltaP: +0.030, ci: '[+0.026, +0.033]', effect: '▲ MLP helpful' },
  { level: '4/7', tokens: 12617, deltaP: +0.014, ci: '[+0.011, +0.016]', effect: '△ MLP marginally helpful' },
  { level: '5/7', tokens: 34155, deltaP: -0.004, ci: '[-0.006, -0.003]', effect: '▽ MLP marginally harmful' },
  { level: '6/7', tokens: 69625, deltaP: -0.014, ci: '[-0.015, -0.014]', effect: '▼ MLP harmful' },
  { level: '7/7', tokens: 77950, deltaP: -0.020, ci: '[-0.021, -0.019]', effect: '▼▼ MLP counterproductive' }
];

const total = 204800;
let output = 'CONSENSUS LEVEL | TOKENS | % | ΔP | EFFECT\n';
output += '─'.repeat(70) + '\n';

for (const l of levels) {
  const pct = (l.tokens / total * 100).toFixed(1);
  const bar = l.deltaP > 0 ? '+'.repeat(Math.round(l.deltaP * 100)) : '-'.repeat(Math.round(-l.deltaP * 100));
  output += `${l.level.padEnd(5)} | ${String(l.tokens).padStart(6)} | ${pct.padStart(5)}% | ${l.deltaP > 0 ? '+' : ''}${l.deltaP.toFixed(3)} ${l.ci} | ${l.effect}\n`;
}

output += '\n─'.repeat(70);
output += '\nCROSSOVER between 4/7 and 5/7: all bootstrap 95% CIs exclude zero.';
output += '\nAt 7/7: MLP promotes 7,674 tokens to top-1 but loses 3,530 — net accuracy gain but net probability LOSS.';
output += '\n\nMoloch\'s Compulsion: The MLP intervenes on EVERY token, even when counterproductive.';
output += '\nThe architecture has no bypass mechanism. 38% of tokens pay full computational cost for negative benefit.';

return output;
